        <span>▰</span>
        <span class="status-dot"></span>
      </div>
    </header>

    <nav id="taskbar" aria-label="Applications">
      <button id="open-files" class="launcher" type="button" aria-label="Files">
        <span class="files-icon" aria-hidden="true"></span>
      </button>
      <button id="open-notepad" class="launcher" type="button" aria-label="Notepad">
        <span class="notepad-icon" aria-hidden="true"></span>
      </button>
    </nav>

    <div class="desktop-caption" aria-hidden="true">
      <strong>Orchid</strong>
      <span>Linux Workspace</span>
    </div>

    <section id="files-window" class="window" aria-label="Files window">
      <header class="titlebar">
        <span class="titlebar-app">Files</span>
        <button class="win-close" type="button" aria-label="Close Files">×</button>
      </header>

      <div class="files-layout window-content">
        <aside class="files-sidebar">
          <div class="sidebar-heading">Places</div>
          <button class="place" type="button" data-path="/">Computer</button>
          <button class="place" type="button" data-path="/home/user">Home</button>
          <button class="place" type="button" data-path="/home/user/Documents">Documents</button>
          <button class="place" type="button" data-path="/home/user/Downloads">Downloads</button>
          <button class="place" type="button" data-path="/home/user/Pictures">Pictures</button>
        </aside>

        <div class="files-main">
          <div class="files-toolbar">
            <button id="files-up" type="button" aria-label="Parent folder" title="Parent folder">↑</button>
            <div id="files-path" aria-label="Current path">/</div>
          </div>
          <div id="files-list" aria-label="Folder contents"></div>
          <div id="files-status">0 items</div>
        </div>
      </div>
    </section>

    <section id="notepad-window" class="window" aria-label="Notepad window">
      <header class="titlebar">
        <span class="titlebar-app">Notepad</span>
        <button class="win-close" type="button" aria-label="Close Notepad">×</button>
      </header>

      <div class="notepad-layout window-content">
        <div class="tabs-bar">
          <div id="tabs" role="tablist" aria-label="Open notes"></div>
          <button id="new-tab" type="button" aria-label="New tab" title="New tab">+</button>
        </div>
        <textarea id="editor" aria-label="Note editor" spellcheck="true"></textarea>
        <div class="editor-status">
          <span id="editor-position">Ln 1, Col 1</span>
          <span id="editor-count">0 characters</span>
        </div>
      </div>
    </section>
