  <script>
    (() => {
      "use strict";

      const desktop = document.getElementById("desktop");
      const filesWindow = document.getElementById("files-window");
      const notepadWindow = document.getElementById("notepad-window");
      const openFiles = document.getElementById("open-files");
      const openNotepad = document.getElementById("open-notepad");
      let topZ = 100;

      function showWindow(windowElement, launcher) {
        windowElement.classList.add("open");
        launcher.classList.add("running");
        bringToFront(windowElement);

        requestAnimationFrame(() => {
          keepWindowVisible(windowElement);
          const focusTarget = windowElement.querySelector("textarea, button, [tabindex]");
          if (focusTarget && windowElement === notepadWindow) {
            document.getElementById("editor").focus();
          }
        });
      }

      function bringToFront(windowElement) {
        topZ += 1;
        windowElement.style.zIndex = String(topZ);
      }

      function keepWindowVisible(windowElement) {
        if (!windowElement.classList.contains("open")) return;
        const rect = windowElement.getBoundingClientRect();
        const maxLeft = Math.max(0, window.innerWidth - Math.min(rect.width, window.innerWidth));
        const maxTop = Math.max(32, window.innerHeight - Math.min(rect.height, window.innerHeight));

        if (rect.left < 0) windowElement.style.left = "0px";
        if (rect.top < 32) windowElement.style.top = "32px";
        if (rect.left > maxLeft) windowElement.style.left = maxLeft + "px";
        if (rect.top > maxTop) windowElement.style.top = maxTop + "px";
      }

      openFiles.addEventListener("click", () => showWindow(filesWindow, openFiles));
      openNotepad.addEventListener("click", () => showWindow(notepadWindow, openNotepad));

      document.querySelectorAll(".window").forEach(windowElement => {
        windowElement.addEventListener("pointerdown", () => bringToFront(windowElement));

        const closeButton = windowElement.querySelector(".win-close");
        closeButton.addEventListener("click", event => {
          event.stopPropagation();
          windowElement.classList.remove("open");
          const launcher = windowElement === filesWindow ? openFiles : openNotepad;
          launcher.classList.remove("running");
          if (windowElement === notepadWindow) saveNotes();
        });
      });

      function makeDraggable(windowElement) {
        const titlebar = windowElement.querySelector(".titlebar");
        let dragging = false;
        let offsetX = 0;
        let offsetY = 0;

        titlebar.addEventListener("pointerdown", event => {
          if (event.target.closest("button")) return;
          dragging = true;
          bringToFront(windowElement);

          const rect = windowElement.getBoundingClientRect();
          offsetX = event.clientX - rect.left;
          offsetY = event.clientY - rect.top;
          titlebar.setPointerCapture(event.pointerId);
          event.preventDefault();
        });

        titlebar.addEventListener("pointermove", event => {
          if (!dragging) return;

          const rect = windowElement.getBoundingClientRect();
          const maxX = Math.max(0, window.innerWidth - rect.width);
          const maxY = Math.max(32, window.innerHeight - rect.height);

          const left = Math.min(Math.max(0, event.clientX - offsetX), maxX);
          const top = Math.min(Math.max(32, event.clientY - offsetY), maxY);

          windowElement.style.left = left + "px";
          windowElement.style.top = top + "px";
        });

        const stopDragging = event => {
          if (!dragging) return;
          dragging = false;
          if (titlebar.hasPointerCapture(event.pointerId)) {
            titlebar.releasePointerCapture(event.pointerId);
          }
        };

        titlebar.addEventListener("pointerup", stopDragging);
        titlebar.addEventListener("pointercancel", stopDragging);
      }

      makeDraggable(filesWindow);
      makeDraggable(notepadWindow);

      window.addEventListener("resize", () => {
        keepWindowVisible(filesWindow);
        keepWindowVisible(notepadWindow);
      });

      function updateClock() {
        const now = new Date();
        document.getElementById("clock").textContent = now.toLocaleString([], {
          weekday: "short",
          month: "short",
          day: "numeric",
          hour: "2-digit",
          minute: "2-digit"
        });
      }

      updateClock();
      setInterval(updateClock, 30000);

      /* Files application */
      const fileSystem = {
        "/": [
          { name: "bin", type: "folder" },
          { name: "etc", type: "folder" },
          { name: "home", type: "folder" },
          { name: "opt", type: "folder" },
          { name: "tmp", type: "folder" },
          { name: "usr", type: "folder" },
          { name: "var", type: "folder" }
        ],
        "/bin": [
          { name: "bash", type: "file" },
          { name: "cat", type: "file" },
          { name: "ls", type: "file" }
        ],
        "/etc": [
          { name: "network", type: "folder" },
          { name: "hosts", type: "file" },
          { name: "os-release", type: "file" }
        ],
        "/etc/network": [
          { name: "interfaces", type: "file" }
        ],
        "/home": [
          { name: "user", type: "folder" }
        ],
        "/home/user": [
          { name: "Documents", type: "folder" },
          { name: "Downloads", type: "folder" },
          { name: "Pictures", type: "folder" },
          { name: "Projects", type: "folder" },
          { name: "welcome.txt", type: "file" }
        ],
        "/home/user/Documents": [
          { name: "Notes.txt", type: "file" },
          { name: "Resume.txt", type: "file" }
        ],
        "/home/user/Downloads": [
          { name: "ubuntu-guide.txt", type: "file" }
        ],
        "/home/user/Pictures": [
          { name: "Wallpapers", type: "folder" },
          { name: "mountains.png", type: "file" }
        ],
        "/home/user/Pictures/Wallpapers": [
          { name: "orchid.png", type: "file" }
        ],
        "/home/user/Projects": [
          { name: "desktop", type: "folder" },
          { name: "README.txt", type: "file" }
        ],
        "/home/user/Projects/desktop": [
          { name: "app.html", type: "file" }
        ],
        "/opt": [],
        "/tmp": [],
        "/usr": [
          { name: "bin", type: "folder" },
          { name: "lib", type: "folder" },
          { name: "share", type: "folder" }
        ],
        "/usr/bin": [
          { name: "editor", type: "file" },
          { name: "files", type: "file" }
        ],
        "/usr/lib": [],
        "/usr/share": [
          { name: "applications", type: "folder" }
        ],
        "/usr/share/applications": [],
        "/var": [
          { name: "log", type: "folder" },
          { name: "tmp", type: "folder" }
        ],
        "/var/log": [
          { name: "system.log", type: "file" }
        ],
        "/var/tmp": []
      };

      const filesPath = document.getElementById("files-path");
      const filesList = document.getElementById("files-list");
      const filesUp = document.getElementById("files-up");
      const filesStatus = document.getElementById("files-status");
      let currentPath = "/";

      function childPath(parent, child) {
        return parent === "/" ? "/" + child : parent + "/" + child;
      }

      function parentPath(path) {
        if (path === "/") return "/";
        const parts = path.split("/").filter(Boolean);
        parts.pop();
        return parts.length ? "/" + parts.join("/") : "/";
      }

      function navigate(path) {
        if (!Object.prototype.hasOwnProperty.call(fileSystem, path)) return;
        currentPath = path;
        renderFiles();
      }

      function renderFiles() {
        const entries = fileSystem[currentPath] || [];
        filesPath.textContent = currentPath;
        filesUp.disabled = currentPath === "/";
        filesList.replaceChildren();

        entries.forEach(entry => {
          const item = document.createElement("button");
          item.type = "button";
          item.className = "fs-item";
          item.dataset.type = entry.type;
          item.dataset.name = entry.name;
          item.textContent = entry.name;
          item.title = entry.type === "folder"
            ? "Double-click to open " + entry.name
            : entry.name;

          item.addEventListener("click", () => {
            filesList.querySelectorAll(".fs-item").forEach(other => {
              other.classList.toggle("selected", other === item);
            });
            filesStatus.textContent = entry.name + " — " + entry.type;
          });

          item.addEventListener("dblclick", () => {
            if (entry.type === "folder") {
              navigate(childPath(currentPath, entry.name));
            } else {
              filesStatus.textContent = entry.name + " is a read-only sample file";
            }
          });

          filesList.appendChild(item);
        });

        filesStatus.textContent = entries.length + (entries.length === 1 ? " item" : " items");

        document.querySelectorAll(".place").forEach(place => {
          place.classList.toggle("active", place.dataset.path === currentPath);
        });
      }

      filesUp.addEventListener("click", () => navigate(parentPath(currentPath)));

      document.querySelectorAll(".place").forEach(place => {
        place.addEventListener("click", () => navigate(place.dataset.path));
      });

      renderFiles();

      /* Notepad application */
      const STORAGE_KEY = "orchid-desktop-notepad-v1";
      const tabsElement = document.getElementById("tabs");
      const newTabButton = document.getElementById("new-tab");
      const editor = document.getElementById("editor");
      const editorPosition = document.getElementById("editor-position");
      const editorCount = document.getElementById("editor-count");

      let notesState = {
        tabs: [],
        activeId: null,
        nextNumber: 1
      };

      function loadNotes() {
        try {
          const stored = localStorage.getItem(STORAGE_KEY);
          if (stored) {
            const parsed = JSON.parse(stored);
            if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length) {
              notesState.tabs = parsed.tabs.map((tab, index) => ({
                id: String(tab.id || "tab-" + (index + 1)),
                title: String(tab.title || "Untitled " + (index + 1)),
                content: typeof tab.content === "string" ? tab.content : ""
              }));
              notesState.activeId = notesState.tabs.some(tab => tab.id === parsed.activeId)
                ? parsed.activeId
                : notesState.tabs[0].id;
              notesState.nextNumber = Number.isFinite(parsed.nextNumber)
                ? Math.max(1, parsed.nextNumber)
                : notesState.tabs.length + 1;
              return;
            }
          }
        } catch (error) {
          console.warn("Could not restore notes:", error);
        }

        notesState = {
          tabs: [
            {
              id: "tab-1",
              title: "Untitled 1",
              content: ""
            }
          ],
          activeId: "tab-1",
          nextNumber: 2
        };
        saveNotes();
      }

      function saveNotes() {
        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(notesState));
        } catch (error) {
          console.warn("Could not save notes:", error);
        }
      }

      function activeTab() {
        return notesState.tabs.find(tab => tab.id === notesState.activeId);
      }

      function renderTabs() {
        tabsElement.replaceChildren();

        notesState.tabs.forEach(tabData => {
          const tab = document.createElement("button");
          tab.type = "button";
          tab.className = "tab";
          tab.dataset.id = tabData.id;
          tab.textContent = tabData.title;
          tab.title = tabData.title;
          tab.setAttribute("role", "tab");
          tab.setAttribute("aria-selected", String(tabData.id === notesState.activeId));

          if (tabData.id === notesState.activeId) {
            tab.classList.add("active");
          }

          tab.addEventListener("click", () => switchTab(tabData.id));
          tabsElement.appendChild(tab);
        });

        const current = activeTab();
        editor.value = current ? current.content : "";
        updateEditorStatus();

        const activeButton = tabsElement.querySelector(".tab.active");
        if (activeButton) activeButton.scrollIntoView({ block: "nearest", inline: "nearest" });
      }

      function switchTab(id) {
        const current = activeTab();
        if (current) current.content = editor.value;

        if (!notesState.tabs.some(tab => tab.id === id)) return;
        notesState.activeId = id;
        saveNotes();
        renderTabs();
        editor.focus();
      }

      function createTab() {
        const number = notesState.nextNumber++;
        const tab = {
          id: "tab-" + Date.now() + "-" + number,
          title: "Untitled " + number,
          content: ""
        };

        notesState.tabs.push(tab);
        notesState.activeId = tab.id;
        saveNotes();
        renderTabs();
        editor.focus();
      }

      function updateEditorStatus() {
        const text = editor.value;
        const selection = editor.selectionStart;
        const beforeCursor = text.slice(0, selection);
        const line = beforeCursor.split("\n").length;
        const lastNewline = beforeCursor.lastIndexOf("\n");
        const column = selection - lastNewline;

        editorPosition.textContent = "Ln " + line + ", Col " + column;
        editorCount.textContent = text.length + (text.length === 1 ? " character" : " characters");
      }

      editor.addEventListener("input", () => {
        const current = activeTab();
        if (current) {
          current.content = editor.value;
          saveNotes();
        }
        updateEditorStatus();
      });

      ["click", "keyup", "select"].forEach(eventName => {
        editor.addEventListener(eventName, updateEditorStatus);
      });

      editor.addEventListener("keydown", event => {
        if (event.key === "Tab") {
          event.preventDefault();
          const start = editor.selectionStart;
          const end = editor.selectionEnd;
          editor.setRangeText("    ", start, end, "end");
          editor.dispatchEvent(new Event("input", { bubbles: true }));
        }

        if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "s") {
          event.preventDefault();
          const current = activeTab();
          if (current) current.content = editor.value;
          saveNotes();
        }
      });

      newTabButton.addEventListener("click", createTab);

      document.addEventListener("keydown", event => {
        if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "n" &&
            notepadWindow.classList.contains("open")) {
          event.preventDefault();
          createTab();
        }
      });

      window.addEventListener("beforeunload", saveNotes);

      loadNotes();
      renderTabs();
    })();
  </script>
